/**
 * @jest-environment jsdom
 */

// Mock the ENV config FIRST before any imports
jest.mock("@/config/env", () => ({
  __esModule: true,
  default: {
    API_BASE_URL: "https://api.test.com",
    API_PREFIX: "/api/v1",
    API_KEY: "test-api-key-12345",
  },
}));

// Mock react-native Platform
jest.mock("react-native", () => ({
  Platform: { OS: "ios" },
}));

// Mock fetch globally BEFORE importing api
const mockFetch = jest.fn();
global.fetch = mockFetch;

// Now import the module under test
import { apiFetch, ApiError } from "../../services/api";

describe("API Service", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockFetch.mockReset();
  });

  it("makes successful API calls", async () => {
    const mockData = { id: 1, name: "Test" };
    mockFetch.mockResolvedValueOnce({
      ok: true,
      status: 200,
      statusText: "OK",
      headers: new Headers({ "content-type": "application/json" }),
      json: async () => mockData,
      text: async () => JSON.stringify(mockData),
    });

    const result = await apiFetch("/test");

    expect(result).toEqual(mockData);
    expect(mockFetch).toHaveBeenCalledWith(
      expect.stringContaining("/test"),
      expect.any(Object)
    );
  });

  it("handles API errors", async () => {
    mockFetch.mockResolvedValueOnce({
      ok: false,
      status: 404,
      statusText: "Not Found",
      headers: new Headers({ "content-type": "application/json" }),
      json: async () => ({ message: "Resource not found" }),
      text: async () => '{"message":"Resource not found"}',
      url: "https://api.test.com/test",
    });

    // The actual implementation throws ApiError
    await expect(apiFetch("/test")).rejects.toThrow();
  });

  it("handles network errors", async () => {
    mockFetch.mockRejectedValueOnce(new Error("Network error"));

    // Catches and re-throws as ApiError
    await expect(apiFetch("/test")).rejects.toThrow();
  });

  it("includes custom headers", async () => {
    mockFetch.mockResolvedValueOnce({
      ok: true,
      status: 200,
      statusText: "OK",
      headers: new Headers({ "content-type": "application/json" }),
      json: async () => ({}),
      text: async () => "{}",
    });

    await apiFetch("/test", {
      headers: { "X-Custom-Header": "test-value" },
    });

    expect(mockFetch).toHaveBeenCalledWith(
      expect.any(String),
      expect.objectContaining({
        headers: expect.any(Object),
      })
    );
  });

  it("handles timeout", async () => {
    // Mock AbortController timeout behavior
    const abortError = new Error("Aborted");
    abortError.name = "AbortError";

    mockFetch.mockRejectedValueOnce(abortError);

    await expect(apiFetch("/test")).rejects.toThrow();
  }, 15000);
});
